features.snippet:
module leaf(input sel, output logic ready);
    always @(sel)
        if ((sel == 1))
            ready = 1;
endmodule

module t;
    leaf d(.sel(i.sel), .ready(i.ready));
endmodule

interface iface(input clk);
    logic sel;
    logic ready;
endinterface

module t;
    logic clk;
    iface i(.clk(clk));
    leaf d(.sel(i.sel), .ready(i.ready));
endmodule
